proof_block:
// The ensures has the shape `(big-conjunction) ==> det_<f>_equal(r1, r2)`.
// The previous attempt asserted each conjunct of the antecedent
// *unconditionally* at the top of the body, but the only requires-hypothesis
// in scope is `MEM_valid(page_entry.addr)`, which does NOT imply, e.g.,
// `usize2present(r1) == page_entry.perm.present`. Those conjuncts are
// *hypotheses* inside the implication, not facts about the proof context.
//
// Fix: pull the antecedent into scope via an `if` whose guard is the entire
// conjunction. Inside the then-branch each conjunct is a hypothesis, so the
// pairwise projection equalities for r1 and r2 are derivable by transitivity
// through the shared `page_entry.perm` / `page_entry.addr` witness. Verus
// then propagates the conditional fact
//     antecedent ==> (each pairwise projection equality)
// past the `if`, which is exactly the observational-equivalence body that
// `det_page_entry2usize_equal(r1, r2)` unfolds to — closing the implication
// in the ensures.
if usize2present(r1) == page_entry.perm.present
    && usize2ps(r1) == page_entry.perm.ps
    && usize2write(r1) == page_entry.perm.write
    && usize2execute_disable(r1) == page_entry.perm.execute_disable
    && usize2user(r1) == page_entry.perm.user
    && usize2pa(r1) == page_entry.addr
    && usize2page_entry_perm(r1) =~= page_entry.perm
    && usize2present(r2) == page_entry.perm.present
    && usize2ps(r2) == page_entry.perm.ps
    && usize2write(r2) == page_entry.perm.write
    && usize2execute_disable(r2) == page_entry.perm.execute_disable
    && usize2user(r2) == page_entry.perm.user
    && usize2pa(r2) == page_entry.addr
    && usize2page_entry_perm(r2) =~= page_entry.perm
{
    // Pairwise projection equalities — transitivity through the shared
    // page_entry.perm / page_entry.addr witness.
    assert(usize2present(r1) == usize2present(r2));
    assert(usize2ps(r1) == usize2ps(r2));
    assert(usize2write(r1) == usize2write(r2));
    assert(usize2execute_disable(r1) == usize2execute_disable(r2));
    assert(usize2user(r1) == usize2user(r2));
    assert(usize2pa(r1) == usize2pa(r2));
    // `=~=` is transitive on PageEntryPerm; both equal page_entry.perm.
    assert(usize2page_entry_perm(r1) =~= usize2page_entry_perm(r2));
}
